import { stdout } from "process";
import { AgentConfig } from "./agent-config.js";
import {
  pruneContext,
  truncateForContext,
  truncateForDisplay,
} from "./context-management.js";
import { logger } from "./logger.js";
import { Message, ToolMessage } from "./message.js";
import { LLMProvider, LLMResponse } from "./providers/llm-provider.js";

type RunnerConstructorProps = {
  llmProvider: LLMProvider;
  agentConfig: AgentConfig;
  maxSteps?: number;
  maxContextTokens?: number;
  signal?: AbortSignal;
  /** Si se provee, las invocaciones a la tool `ask_user` pausan el runner
   * y llaman a este callback. La respuesta se inyecta como tool_result. */
  onAskUser?: (question: string) => Promise<string>;
};

type RunnerEvent =
  | { type: "text"; text: string }
  | { type: "text_stream"; text: string }
  | { type: "text_stream_end" }
  | { type: "state"; message: Message }
  | { type: "tool_use"; name: string; input: unknown }
  | {
      type: "tool_result";
      output: string;
      /** Output completo (sin truncar) para poder mostrar un resumen real. */
      rawOutput?: string;
    }
  | { type: "ask_user"; question: string; toolId: string };

/** Estado mutable que comparten los métodos de un turno del loop. */
interface TurnState {
  textParts: string[];
  toolBlocks: Array<{ id: string; name: string; input: unknown }>;
  toolResults: ToolMessage[];
  stopReason: "end_turn" | "tool_use" | "max_tokens";
}

class Runner {
  // Métricas de una sola corrida (se resetean con resetMetrics()).
  // El acumulado histórico lo mantiene Session (addUsage), que es el
  // único dueño persistente del costo total.
  #llmProvider: LLMProvider;
  #agentConfig: AgentConfig;
  #maxSteps: number;
  #maxContextTokens: number;
  #signal: AbortSignal | undefined;
  #interrupted: boolean;
  #onAskUser: ((question: string) => Promise<string>) | undefined;
  #metrics: {
    totalInputTokens: number;
    totalOutputTokens: number;
    totalToolCalls: number;
    totalCost: number;
    startTime: number;
  };

  constructor({
    llmProvider,
    agentConfig,
    maxSteps = 15,
    maxContextTokens = 100_000,
    signal,
    onAskUser,
  }: RunnerConstructorProps) {
    this.#llmProvider = llmProvider;
    this.#agentConfig = agentConfig;
    this.#maxSteps = maxSteps;
    this.#maxContextTokens = maxContextTokens;
    this.#signal = signal;
    this.#interrupted = false;
    this.#onAskUser = onAskUser;
    this.#metrics = {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      totalToolCalls: 0,
      totalCost: 0,
      startTime: Date.now(),
    };
  }

  /** Expone si el runner fue interrumpido (SIGINT) — el caller lo usa para
   * saber si debe guardar métricas parciales o descartarlas. */
  get interrupted(): boolean {
    return this.#interrupted;
  }

  // ── helpers ────────────────────────────────────────────────────────

  /**
   * Arma el contenido del mensaje assistant a partir de lo producido
   * en el turno. Si no hay nada visible, pone un fallback.
   */
  #buildAssistantContent(state: TurnState): Message["content"] {
    const content: Message["content"] = [];
    if (state.textParts.length > 0) {
      content.push({ type: "text", text: state.textParts.join("") });
    }
    for (const tb of state.toolBlocks) {
      content.push({
        type: "tool_use",
        id: tb.id,
        name: tb.name,
        input: tb.input,
      });
    }
    if (content.length === 0) {
      content.push({
        type: "text",
        text: "(El modelo no produjo contenido visible en este turno)",
      });
    }
    return content;
  }

  /** Construye el snapshot del estado vacío para un turno nuevo. */
  #newTurnState(): TurnState {
    return {
      textParts: [],
      toolBlocks: [],
      toolResults: [],
      stopReason: "end_turn",
    };
  }

  // ── fases del turno ────────────────────────────────────────────────

  /** Llama al LLM (stream o no-stream), emite eventos y llena `state`. */
  async *#callLLM(
    prunedContext: Message[],
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    const hasStream = typeof this.#llmProvider.callStream === "function";

    if (hasStream) {
      const stream = this.#llmProvider.callStream(
        prunedContext,
        this.#agentConfig,
        this.#signal,
      );

      for await (const event of stream) {
        if (event.type === "text") {
          state.textParts.push(event.text);
          yield { type: "text_stream", text: event.text };
        } else if (event.type === "tool_use") {
          state.toolBlocks.push({
            id: event.id,
            name: event.name,
            input: event.input,
          });
        } else if (event.type === "done") {
          state.stopReason = event.stop_reason;
          this.#metrics.totalInputTokens += event.usage.input_tokens;
          this.#metrics.totalOutputTokens += event.usage.output_tokens;
          this.#metrics.totalCost += event.cost;
        }
      }

      if (state.textParts.length > 0) {
        yield { type: "text_stream_end" };
      }
    } else {
      const data: LLMResponse = await this.#llmProvider.call(
        prunedContext,
        this.#agentConfig,
        this.#signal,
      );

      this.#metrics.totalInputTokens += data.usage.input_tokens;
      this.#metrics.totalOutputTokens += data.usage.output_tokens;
      this.#metrics.totalCost += data.cost;

      for (const block of data.content) {
        if (block.type === "text") {
          state.textParts.push(block.text);
          yield { type: "text", text: block.text };
        }
        if (block.type === "tool_use") {
          state.toolBlocks.push({
            id: block.id,
            name: block.name,
            input: block.input,
          });
        }
      }

      state.stopReason = data.stop_reason;
    }
  }

  /** Ejecuta las tool calls pendientes, emite eventos y llena `state.toolResults`.
   *
   * Las tools regulares se ejecutan en paralelo (Promise.allSettled).
   * Los tool_use se emiten todos primero; los tool_result se emiten en
   * el orden original de los tool_use, preservando consistencia.
   * ask_user se ejecuta siempre secuencial. */
  async *#executeTools(state: TurnState): AsyncGenerator<RunnerEvent> {
    // 1. Separar ask_user del resto y emitir tool_use en orden
    for (const block of state.toolBlocks) {
      yield { type: "tool_use", name: block.name, input: block.input };
    }

    // 2. Lanzar tools regulares en paralelo (sin esperar aún)
    const regularBlocks = state.toolBlocks.filter((b) => b.name !== "ask_user");
    this.#metrics.totalToolCalls += regularBlocks.length;

    const pending = new Map(
      regularBlocks.map((block) => {
        const promise = this.#executeOneTool(block.name, block.id, block.input);
        return [block.id, promise];
      }),
    );

    // 3. Procesar en orden original: ask_user secuencial, tools resueltas
    for (const block of state.toolBlocks) {
      if (block.name === "ask_user") {
        yield* this.#handleAskUser(block, state);
        continue;
      }

      const result = await pending.get(block.id)!;
      const shown = truncateForDisplay(result.output);
      const forModel = truncateForContext(result.output, this.#maxContextTokens);

      yield { type: "tool_result", output: shown, rawOutput: result.output };
      state.toolResults.push({
        type: "tool_result",
        tool_use_id: block.id,
        content: forModel,
        is_error: result.isError,
      });
    }
  }

  /** Ejecuta una sola tool y devuelve output + flag de error. */
  async #executeOneTool(
    name: string,
    id: string,
    input: unknown,
  ): Promise<{ output: string; isError: boolean }> {
    const tool = this.#agentConfig.getTool(name);
    if (!tool) {
      const msg = `Error: unknown tool "${name}"`;
      logger.error(msg);
      return { output: msg, isError: true };
    }
    try {
      return { output: tool.execute(input) as string, isError: false };
    } catch (err: unknown) {
      const msg = `Error executing tool "${name}": ${err instanceof Error ? err.message : String(err)}`;
      logger.error("Tool execution threw", { tool: name, error: msg });
      return { output: msg, isError: true };
    }
  }

  // ── sub-fases de executeTools ──────────────────────────────────────

  async *#handleAskUser(
    block: { id: string; name: string; input: unknown },
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    if (!this.#onAskUser) return;

    const question =
      (block.input as { question?: string }).question ?? "¿Continuar?";
    yield { type: "ask_user", question, toolId: block.id };

    const answer = await this.#onAskUser(question);
    const output = answer || "(sin respuesta)";
    yield {
      type: "tool_result",
      output: "(confirmación recibida)",
      rawOutput: output,
    };
    state.toolResults.push({
      type: "tool_result",
      tool_use_id: block.id,
      content: output,
      is_error: false,
    });
  }

  // ── loop principal ─────────────────────────────────────────────────

  async *run(incomingContext: readonly Message[]): AsyncGenerator<RunnerEvent> {
    const workingContext = [...incomingContext];
    logger.info(`Starting runner with max steps: ${this.#maxSteps}`);

    let steps = this.#maxSteps;
    while (steps > 0) {
      if (this.#signal?.aborted) {
        this.#interrupted = true;
        logger.info("Runner interrupted by abort signal");
        yield { type: "text", text: "⏹ Interrumpido por el usuario." };
        break;
      }

      const prunedContext = pruneContext(
        workingContext,
        this.#maxContextTokens,
      );

      const state = this.#newTurnState();

      try {
        yield* this.#callLLM(prunedContext, state);
      } catch (err: unknown) {
        if (err instanceof Error && err.name === "AbortError") {
          this.#interrupted = true;
          logger.info("LLM call aborted by signal");
          yield { type: "text", text: "⏹ Interrumpido por el usuario." };
          const partialMessage: Message = {
            role: "assistant",
            content: this.#buildAssistantContent(state),
          };
          workingContext.push(partialMessage);
          yield { type: "state", message: partialMessage };
          break;
        }
        throw err;
      }

      // Agregar mensaje assistant al contexto
      const assistantMessage: Message = {
        role: "assistant",
        content: this.#buildAssistantContent(state),
      };
      workingContext.push(assistantMessage);
      yield { type: "state", message: assistantMessage };

      // Ejecutar tools
      yield* this.#executeTools(state);

      if (state.toolResults.length > 0) {
        const toolMessage: Message = {
          role: "user",
          content: state.toolResults,
        };
        workingContext.push(toolMessage);
        yield { type: "state", message: toolMessage };
      }

      if (state.stopReason === "max_tokens") {
        logger.warn("Respuesta cortada por max_tokens");
        yield {
          type: "text",
          text: "⚠ La respuesta se cortó (max_tokens). Subí el límite o pedí algo más chico.",
        };
        break;
      }

      if (state.stopReason === "end_turn") {
        logger.info("Agent finished (end_turn)");
        break;
      }

      steps--;
      if (steps === 0) {
        logger.warn(`Max steps reached (${this.#maxSteps})`);
      }
    }
  }

  getMetrics() {
    return {
      ...this.#metrics,
      durationMs: Date.now() - this.#metrics.startTime,
    };
  }

  resetMetrics() {
    this.#metrics = {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      totalToolCalls: 0,
      totalCost: 0,
      startTime: Date.now(),
    };
  }
}

export { Runner, RunnerEvent };

import { describe, it, expect, beforeEach } from "vitest";
import { Runner } from "../runner.js";
import { AgentConfig } from "../agent-config.js";
import { LLMProvider, LLMResponse, StreamEvent } from "../providers/llm-provider.js";
import { BashTool } from "../tools/bash.js";
import { ReadTool } from "../tools/read.js";
import { Message } from "../message.js";

// ── Mock LLM Provider ────────────────────────────────────────────────────────

class MockLLMProvider extends LLMProvider {
  #responses: LLMResponse[];
  #callCount = 0;

  constructor(responses: LLMResponse[]) {
    super({ apiKey: "mock-key", url: "http://mock" });
    this.#responses = responses;
  }

  async call(_messages: Message[], _agent: AgentConfig): Promise<LLMResponse> {
    const resp = this.#responses[this.#callCount % this.#responses.length];
    this.#callCount++;
    return resp;
  }

  async *callStream(_messages: Message[], _agent: AgentConfig): AsyncGenerator<StreamEvent> {
    const resp = this.#responses[this.#callCount % this.#responses.length];
    this.#callCount++;

    for (const block of resp.content) {
      if (block.type === "text") {
        yield { type: "text", text: block.text };
      }
      if (block.type === "tool_use") {
        yield { type: "tool_use", id: block.id, name: block.name, input: block.input };
      }
    }

    yield {
      type: "done",
      stop_reason: resp.stop_reason,
      usage: resp.usage,
      cost: resp.cost,
    };
  }
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function mockAgent(): AgentConfig {
  const agent = new AgentConfig({
    systemPrompt: "Test",
    model: "claude-haiku-4-5-20251001",
    maxTokens: 1024,
  });
  agent.addTool(new BashTool());
  agent.addTool(new ReadTool());
  return agent;
}

function textResponse(text: string): LLMResponse {
  return {
    content: [{ type: "text", text }],
    stop_reason: "end_turn",
    usage: { input_tokens: 10, output_tokens: 5 },
    cost: 0.0001,
  };
}

function toolUseResponse(
  toolCalls: Array<{ id: string; name: string; input: unknown }>,
): LLMResponse {
  return {
    content: toolCalls.map((tc) => ({
      type: "tool_use" as const,
      ...tc,
    })),
    stop_reason: "tool_use",
    usage: { input_tokens: 20, output_tokens: 10 },
    cost: 0.0002,
  };
}

function mixedResponse(
  text: string,
  toolCalls: Array<{ id: string; name: string; input: unknown }>,
): LLMResponse {
  return {
    content: [
      { type: "text" as const, text },
      ...toolCalls.map((tc) => ({ type: "tool_use" as const, ...tc })),
    ],
    stop_reason: "tool_use",
    usage: { input_tokens: 30, output_tokens: 15 },
    cost: 0.0003,
  };
}

async function collectEvents(runner: Runner, context: Message[]): Promise<Array<{ type: string; name?: string }>> {
  const events: Array<{ type: string; name?: string }> = [];
  for await (const event of runner.run(context)) {
    events.push({ type: event.type, name: "name" in event ? (event as { name: string }).name : undefined });
  }
  return events;
}

// ── Tests ────────────────────────────────────────────────────────────────────

describe("Runner", () => {
  describe("single text response", () => {
    it("should emit text and state events for a simple text response", async () => {
      const provider = new MockLLMProvider([textResponse("Hello!")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "Hi" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "text_stream")).toBe(true);
      expect(events.some((e) => e.type === "text_stream_end")).toBe(true);
      expect(events.some((e) => e.type === "state")).toBe(true);
    });

    it("should not emit tool_use events for text-only response", async () => {
      const provider = new MockLLMProvider([textResponse("Done")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "x" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_use")).toBe(false);
      expect(events.some((e) => e.type === "tool_result")).toBe(false);
    });
  });

  describe("tool use response", () => {
    it("should execute tool and emit tool_result", async () => {
      // 1st: tool_use, 2nd: end_turn
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "bash", input: { command: "echo hello" } }]),
        textResponse("Tool executed."),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "run echo" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_use")).toBe(true);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });

    it("should handle unknown tool gracefully", async () => {
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "nonexistent_tool", input: {} }]),
        textResponse("Done"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "use unknown tool" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });

    it("should handle mixed text + tool_use", async () => {
      const provider = new MockLLMProvider([
        mixedResponse("Let me check...", [
          { id: "t1", name: "bash", input: { command: "pwd" } },
        ]),
        textResponse("All done."),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "where am I?" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "text_stream")).toBe(true);
      expect(events.some((e) => e.type === "tool_use")).toBe(true);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });
  });

  describe("max_tokens stop reason", () => {
    it("should emit warning text on max_tokens", async () => {
      const provider = new MockLLMProvider([{
        content: [{ type: "text", text: "Partial..." }],
        stop_reason: "max_tokens",
        usage: { input_tokens: 10, output_tokens: 5 },
        cost: 0.0001,
      }]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "big task" }];

      const events: string[] = [];
      for await (const event of runner.run(context)) {
        if (event.type === "text") {
          events.push(event.text);
        }
      }
      const warning = events.find((t) => t.includes("cortó"));
      expect(warning).toBeDefined();
    });
  });

  describe("metrics", () => {
    it("should accumulate token usage and cost", async () => {
      const provider = new MockLLMProvider([
        textResponse("First"),
        textResponse("Second"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "multi" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      const metrics = runner.getMetrics();
      expect(metrics.totalInputTokens).toBeGreaterThan(0);
      expect(metrics.totalOutputTokens).toBeGreaterThan(0);
      expect(metrics.totalCost).toBeGreaterThan(0);
      expect(metrics.totalToolCalls).toBe(0);
      expect(metrics.durationMs).toBeGreaterThanOrEqual(0);
    });

    it("should count tool calls", async () => {
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "bash", input: { command: "echo a" } }]),
        textResponse("Done"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "run cmd" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      expect(runner.getMetrics().totalToolCalls).toBe(1);
    });
  });

  describe("max steps", () => {
    it("should stop after maxSteps", async () => {
      // Cada respuesta pide tool_use -> el loop consumiría steps hasta el límite
      const responses: LLMResponse[] = [];
      for (let i = 0; i < 20; i++) {
        responses.push(
          toolUseResponse([{ id: `t${i}`, name: "bash", input: { command: "echo x" } }]),
        );
      }
      const provider = new MockLLMProvider(responses);
      const runner = new Runner({
        llmProvider: provider,
        agentConfig: mockAgent(),
        maxSteps: 3,
      });
      const context: Message[] = [{ role: "user", content: "loop" }];

      let toolUseCount = 0;
      for await (const event of runner.run(context)) {
        if (event.type === "tool_use") toolUseCount++;
      }

      // Con maxSteps=3, el loop hace 3 iteraciones de tool_use
      expect(toolUseCount).toBeLessThanOrEqual(3);
    });
  });

  describe("resetMetrics", () => {
    it("should reset all metrics to zero", async () => {
      const provider = new MockLLMProvider([textResponse("Hi")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "x" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      runner.resetMetrics();
      const metrics = runner.getMetrics();
      expect(metrics.totalInputTokens).toBe(0);
      expect(metrics.totalOutputTokens).toBe(0);
      expect(metrics.totalToolCalls).toBe(0);
      expect(metrics.totalCost).toBe(0);
    });
  });
});

import { stdout } from "process";
import { AgentConfig } from "./agent-config.js";
import {
  pruneContext,
  truncateForContext,
  truncateForDisplay,
} from "./context-management.js";
import { logger } from "./logger.js";
import { Message, ToolMessage } from "./message.js";
import { LLMProvider, LLMResponse } from "./providers/llm-provider.js";

import { Tool } from "./tools/tool.js";

type AgentConfigConstructorProps = {
  systemPrompt: string;
  model: string;
  maxTokens: number;
};

class AgentConfig {
  #systemPrompt: string;

import { execSync } from "child_process";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";

type BashInput = { command: string };

const TIMEOUT_MS = 30_000; // matar comandos colgados a los 30s
const MAX_BUFFER = 10 * 1024 * 1024; // 10MB de stdout/stderr

// Esto NO es un sandbox: es un guardarraíl best-effort contra los
// errores más groseros. Un comando malicioso decidido lo puede saltar.
// Para aislamiento real haría falta correr en un contenedor/VM.
const BLOCKED_PATTERNS = [
  /\brm\s+-[a-z]*[rf]/i, // rm con -r o -f en cualquier orden/combinación
  /:\s*\(\s*\)\s*\{.*:.*\|.*:.*\}/, // fork bomb
  />\s*\/dev\/(sd|nvme|disk|hd)/i, // escritura directa a un disco
  /\bmkfs\b/i, // formatear un filesystem
  /\bdd\b.*\bof=\/dev\//i, // dd hacia un device
  /\b(shutdown|reboot|halt|poweroff)\b/i, // apagar/reiniciar la máquina
];

// Patrones que involucran archivos .env (lectura o escritura)
const ENV_ACCESS_PATTERNS = [
  /(^|[|&;`\s])(cat|head|tail|less|more|bat|nl|od|strings)\s+.*\.env\b/i,
  /(^|[|&;`\s])(cp|mv)\s+.*\.env\b/i,
  /(^|[|&;`\s])(cp|mv)\s+\S+\s+.*\.env\b/i,
  />>>?\s*.*\.env\b/i,        // > .env, >> .env
  /(^|[|&;`\s])echo\s+.*>>>?\s*.*\.env\b/i,
  /(^|[|&;`\s])tee\s+.*\.env\b/i,
  /(^|[|&;`\s])(grep|rg|awk|sed|cut|sort|uniq|diff|comm|join|paste)\s+.*\.env\b/i,
  /\.env[\s'"]*$/i,            // cualquier comando cuyo último arg sea .env
];

export class BashTool extends Tool<BashInput, string> {
  constructor() {
    super({
      name: "bash",
      description: "Ejecuta un comando bash y devuelve stdout y stderr",
      schema: {
        type: "object",
        properties: {
          command: {
            type: "string",
            description: "El comando bash a ejecutar",
          },
        },
        required: ["command"],
      },
    });
  }

  private isCommandBlocked(command: string): boolean {
    return BLOCKED_PATTERNS.some((pattern) => pattern.test(command))
      || ENV_ACCESS_PATTERNS.some((pattern) => pattern.test(command));
  }

  execute({ command }: BashInput): string {
    try {
      if (!command || typeof command !== "string") {
        logger.error("Invalid bash command input", { command });
        return "Error: command must be a non-empty string";
      }

      if (this.isCommandBlocked(command)) {
        logger.warn("Blocked dangerous command", { command });
        return "Error: This command is blocked for security reasons";
      }

      logger.info("Executing bash command", { command });
      const result = execSync(command, {
        encoding: "utf-8",
        timeout: TIMEOUT_MS,
        maxBuffer: MAX_BUFFER,
      });
      logger.info("Command executed successfully");
      return result;
    } catch (err: unknown) {
      const error = err as { code?: string; signal?: string; stderr?: string; stdout?: string; message?: string };
      if (error.code === "ETIMEDOUT" || error.signal === "SIGTERM") {
        const msg = `Error: command timed out after ${TIMEOUT_MS}ms`;
        logger.warn("Bash command timed out", { command });
        return msg;
      }
      const errorMsg = error.stderr || error.stdout || error.message || String(err);
      logger.error("Bash command failed", { command, error: errorMsg });
      return errorMsg;
    }
  }
}

type ToolConstructorProps = {
  name: string;
  description: string;
  schema: Record<string, unknown>;
};

export abstract class Tool<Tin, Tout> {
  #name: string;
  #description: string;
  #schema: Record<string, unknown>;

  constructor({ name, description, schema }: ToolConstructorProps) {
    this.#name = name;
    this.#description = description;
    this.#schema = schema;
  }

  abstract execute(input: Tin): Tout;

  get name() {
    return this.#name;
  }

  toJSON() {
    return {
      name: this.#name,
      description: this.#description,
      input_schema: this.#schema,
    };
  }
}

import { readFileSync } from "fs";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";
import { isEnvFile, ENV_BLOCK_MESSAGE } from "./env-guard.js";

type ReadInput = { path: string; offset?: number; limit?: number };

export class ReadTool extends Tool<ReadInput, string> {
  constructor() {
    super({
      name: "read",
      description: "Devuelve el contenido de un archivo",
      schema: {
        type: "object",
        properties: {
          path: { type: "string", description: "Ruta del archivo a leer" },
          offset: {
            type: "number",
            description: "Línea desde la que empezar (1-indexed, opcional)",
          },
          limit: {
            type: "number",
            description: "Máximo de líneas a leer (opcional)",
          },
        },
        required: ["path"],
      },
    });
  }

  execute(input: unknown): string {
    try {
      if (typeof input !== "object" || input === null) {
        throw new Error("Input must be an object with path");
      }

      const { path, offset, limit } = input as ReadInput;

      if (typeof path !== "string" || !path.trim()) {
        throw new Error("path must be a non-empty string");
      }

      if (isEnvFile(path)) {
        logger.warn("Blocked read of env file", { path });
        return ENV_BLOCK_MESSAGE;
      }

      logger.info("Reading file", { path, offset, limit });
      const content = readFileSync(path, "utf-8");

      // sin offset/limit: devolvemos el archivo entero
      if (offset === undefined && limit === undefined) {
        logger.info("File read successfully", { path, lines: content.split("\n").length });
        return content;
      }

      const lines = content.split("\n");
      const start = offset ? offset - 1 : 0; // offset es 1-indexed
      const end = limit ? start + limit : lines.length;
      const result = lines.slice(start, end).join("\n");
      logger.info("File slice read successfully", { path, start, end });
      return result;
    } catch (err: unknown) {
      const pathName = input !== null && typeof input === "object" && "path" in (input as object)
        ? String((input as ReadInput).path)
        : String(input);
      const errorMsg = `Error reading ${pathName}: ${err instanceof Error ? err.message : String(err)}`;
      logger.error(errorMsg);
      return errorMsg;
    }
  }
}

import { writeFileSync, mkdirSync } from "fs";
import { dirname } from "path";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";
import { isEnvFile, ENV_BLOCK_MESSAGE } from "./env-guard.js";

type WriteInput = { path: string; content: string };

export class WriteTool extends Tool<WriteInput, string> {
  constructor() {
    super({
      name: "write",
      description:
        "Crea un archivo nuevo o sobrescribe uno existente con el contenido dado",
      schema: {
        type: "object",
        properties: {
          path: { type: "string", description: "Ruta del archivo a escribir" },
          content: {
            type: "string",
            description: "Contenido completo a escribir en el archivo",
          },
        },
        required: ["path", "content"],
      },
    });
  }

  execute(input: unknown): string {
    try {
      // Validar que input es un objeto
      if (typeof input !== "object" || input === null) {
        throw new Error("Input must be an object with path and content");
      }

      const { path, content } = input as Record<string, unknown>;

      // Validar tipos
      if (typeof path !== "string" || typeof content !== "string") {
        throw new Error("path and content must be strings");
      }

      if (!path.trim()) {
        throw new Error("path cannot be empty");
      }

      if (isEnvFile(path)) {
        logger.warn("Blocked write to env file", { path });
        return ENV_BLOCK_MESSAGE;
      }

      logger.info("Writing file", { path, size: content.length });
      mkdirSync(dirname(path), { recursive: true });
      writeFileSync(path, content, "utf-8");
      logger.info("File written successfully", { path });
      return `Escrito ${path} correctamente.`;
    } catch (err: unknown) {
      const errorMsg = `Error writing file: ${err instanceof Error ? err.message : String(err)}`;
      logger.error(errorMsg, { error: err });
      return errorMsg;
    }
  }
}

import { readFileSync, writeFileSync } from "fs";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";
import { isEnvFile, ENV_BLOCK_MESSAGE } from "./env-guard.js";

export type EditInput = { path: string; oldText: string; newText: string };

export class EditTool extends Tool<EditInput, string> {
  constructor() {
    super({
      name: "edit",
      description: "Reemplaza quirúrgicamente texto exacto dentro de un archivo",
      schema: {
        type: "object",
        properties: {
          path: { type: "string", description: "Ruta del archivo a editar" },
          oldText: {
            type: "string",
            description:
              "Texto exacto a reemplazar (debe matchear carácter por carácter, incluido el whitespace)",
          },
          newText: {
            type: "string",
            description: "Texto nuevo que reemplaza al viejo",
          },
        },
        required: ["path", "oldText", "newText"],
      },
    });
  }

  execute(input: unknown): string {
    try {
      if (typeof input !== "object" || input === null) {
        throw new Error("Input must be an object with path, oldText, and newText");
      }

      const { path, oldText, newText } = input as EditInput;

      if (typeof path !== "string" || typeof oldText !== "string" || typeof newText !== "string") {
        throw new Error("path, oldText, and newText must be strings");
      }

      if (isEnvFile(path)) {
        logger.warn("Blocked edit of env file", { path });
        return ENV_BLOCK_MESSAGE;
      }

      logger.info("Editing file", { path, oldTextLength: oldText.length, newTextLength: newText.length });

      let content: string;
      try {
        content = readFileSync(path, "utf-8");
      } catch (err: unknown) {
        throw new Error(`Could not read ${path}: ${err instanceof Error ? err.message : String(err)}`);
      }

      const occurrences = content.split(oldText).length - 1;

      if (occurrences === 0) {
        logger.warn("Text not found in file", { path });
        throw new Error(`Text to replace not found in ${path}. Ensure it matches exactly.`);
      }

      if (occurrences > 1) {
        logger.warn("Multiple occurrences found", { path, occurrences });
        throw new Error(`Text appears ${occurrences} times in ${path}, ambiguous. Include more context.`);
      }

      const updated = content.replace(oldText, newText);
      try {
        writeFileSync(path, updated, "utf-8");
      } catch (err: unknown) {
        throw new Error(`Could not write ${path}: ${err instanceof Error ? err.message : String(err)}`);
      }

      logger.info("File edited successfully", { path });
      return `Editado ${path} correctamente.`;
    } catch (err: unknown) {
      const errorMsg = err instanceof Error ? err.message : `Unknown error editing file`;
      logger.error(errorMsg, { error: err });
      return `Error: ${errorMsg}`;
    }
  }
}

