import { describe, it, expect, beforeEach } from "vitest";
import { BashTool } from "../../tools/bash.js";

describe("BashTool", () => {
  let bashTool: BashTool;

  beforeEach(() => {
    bashTool = new BashTool();
  });

  it("should execute simple commands", () => {
    const result = bashTool.execute({ command: "echo hello" });
    expect(result).toContain("hello");
  });

  it("should execute ls command", () => {
    const result = bashTool.execute({ command: "ls -la src" });
    expect(result).toBeTruthy();
  });

  it("should handle command errors gracefully", () => {
    const result = bashTool.execute({ command: "false" });
    expect(result).toBeTruthy(); // Returns error output
  });

  it("should block dangerous commands", () => {
    const result = bashTool.execute({ command: "rm -rf /" });
    expect(result).toContain("blocked");
  });

  it("should block fork bomb pattern", () => {
    const result = bashTool.execute({ command: ":() { :|:& };" });
    expect(result).toContain("blocked");
  });

  it("should validate command input", () => {
    const result = bashTool.execute({ command: "" });
    expect(result).toContain("Error");
  });

  it("should validate input type", () => {
    const result = bashTool.execute({ command: null } as any);
    expect(result).toContain("Error");
  });

  it("should allow safe commands", () => {
    const result = bashTool.execute({ command: "pwd" });
    expect(result).toBeTruthy();
    expect(result).not.toContain("blocked");
  });
});

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { writeFileSync, unlinkSync } from "fs";
import { ReadTool } from "../../tools/read.js";

describe("ReadTool", () => {
  const testFile = "./test-file-read.txt";
  let readTool: ReadTool;

  beforeEach(() => {
    readTool = new ReadTool();
    const content = "Line 1\nLine 2\nLine 3\nLine 4\nLine 5";
    writeFileSync(testFile, content, "utf-8");
  });

  afterEach(() => {
    try {
      unlinkSync(testFile);
    } catch {
      // File doesn't exist
    }
  });

  it("should read entire file content", () => {
    const result = readTool.execute({ path: testFile });
    expect(result).toContain("Line 1");
    expect(result).toContain("Line 5");
  });

  it("should read with offset and limit", () => {
    const result = readTool.execute({ path: testFile, offset: 2, limit: 2 });
    const lines = result.split("\n");
    expect(lines[0]).toBe("Line 2");
    expect(lines[1]).toBe("Line 3");
  });

  it("should handle offset only", () => {
    const result = readTool.execute({ path: testFile, offset: 3 });
    expect(result).toContain("Line 3");
    expect(result).toContain("Line 4");
    expect(result).toContain("Line 5");
  });

  it("should handle invalid path", () => {
    const result = readTool.execute({ path: "./non-existent-file.txt" });
    expect(result).toContain("Error");
  });

  it("should validate input type", () => {
    const result = readTool.execute({
      path: "",
    } as any);
    expect(result).toContain("Error");
  });
});

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { readFileSync, unlinkSync, rmSync } from "fs";
import { WriteTool } from "../../tools/write.js";

describe("WriteTool", () => {
  const testFile = "./test-file-write.txt";
  const testDir = "./test-dir-write";
  let writeTool: WriteTool;

  beforeEach(() => {
    writeTool = new WriteTool();
  });

  afterEach(() => {
    try {
      unlinkSync(testFile);
    } catch {
      // File doesn't exist
    }
    try {
      rmSync(testDir, { recursive: true, force: true });
    } catch {
      // Dir doesn't exist
    }
  });

  it("should create a new file", () => {
    const content = "Test content";
    const result = writeTool.execute({ path: testFile, content });
    expect(result).toContain("correctamente");
    const fileContent = readFileSync(testFile, "utf-8");
    expect(fileContent).toBe(content);
  });

  it("should overwrite existing file", () => {
    writeTool.execute({ path: testFile, content: "Original" });
    writeTool.execute({ path: testFile, content: "Updated" });
    const content = readFileSync(testFile, "utf-8");
    expect(content).toBe("Updated");
  });

  it("should create nested directories", () => {
    const nestedPath = `${testDir}/nested/path/file.txt`;
    const result = writeTool.execute({
      path: nestedPath,
      content: "Nested content",
    });
    expect(result).toContain("correctamente");
    const fileContent = readFileSync(nestedPath, "utf-8");
    expect(fileContent).toBe("Nested content");
  });

  it("should validate path is not empty", () => {
    const result = writeTool.execute({ path: "", content: "Test" });
    expect(result).toContain("Error");
  });

  it("should validate input types", () => {
    const result = writeTool.execute({
      path: 123,
      content: "Test",
    } as any);
    expect(result).toContain("Error");
  });

  it("should handle large content", () => {
    const largeContent = "x".repeat(10000);
    const result = writeTool.execute({ path: testFile, content: largeContent });
    expect(result).toContain("correctamente");
    const fileContent = readFileSync(testFile, "utf-8");
    expect(fileContent.length).toBe(10000);
  });
});

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { writeFileSync, readFileSync, unlinkSync } from "fs";
import { EditTool, type EditInput } from "../../tools/edit.js";

describe("EditTool", () => {
  const testFile = "./test-file-edit.txt";
  let editTool: EditTool;

  beforeEach(() => {
    editTool = new EditTool();
    writeFileSync(testFile, "Line 1\nLine 2\nLine 3\nLine 4\nLine 5", "utf-8");
  });

  afterEach(() => {
    try {
      unlinkSync(testFile);
    } catch {
      // File doesn't exist
    }
  });

  it("should replace exact text in a file", () => {
    const result = editTool.execute({
      path: testFile,
      oldText: "Line 2",
      newText: "Line 2 MODIFIED",
    });
    expect(result).toContain("Editado");
    expect(result).toContain(testFile);

    const content = readFileSync(testFile, "utf-8");
    expect(content).toContain("Line 2 MODIFIED");
    expect(content).not.toContain("Line 2\n");
  });

  it("should fail when text not found (0 occurrences)", () => {
    const result = editTool.execute({
      path: testFile,
      oldText: "This text does not exist",
      newText: "replacement",
    });
    expect(result).toContain("Error");
    expect(result).toContain("not found");
  });

  it("should fail on multiple occurrences (ambiguous)", () => {
    const result = editTool.execute({
      path: testFile,
      oldText: "Line",
      newText: "Row",
    });
    expect(result).toContain("Error");
    expect(result).toContain("ambiguous");
    expect(result).toContain("5 times");
  });

  it("should fail on non-existent file", () => {
    const result = editTool.execute({
      path: "./does-not-exist-xyz.txt",
      oldText: "anything",
      newText: "else",
    });
    expect(result).toContain("Error");
