import { describe, it, expect, beforeEach } from "vitest";
import { BashTool } from "../../tools/bash.js";

describe("BashTool", () => {
  let bashTool: BashTool;

  beforeEach(() => {
    bashTool = new BashTool();
  });

  it("should execute simple commands", async () => {
    const result = await bashTool.execute({ command: "echo hello" });
    expect(result).toContain("hello");
  });

  it("should execute ls command", async () => {
    const result = await bashTool.execute({ command: "ls -la src" });
    expect(result).toBeTruthy();
  });

  it("should handle command errors gracefully", async () => {
    const result = await bashTool.execute({ command: "false" });
    expect(result).toBeTruthy(); // Returns error output
  });

  it("should block dangerous commands", async () => {
    const result = await bashTool.execute({ command: "rm -rf /" });
    expect(result).toContain("blocked");
  });

  it("should block fork bomb pattern", async () => {
    const result = await bashTool.execute({ command: ":() { :|:& };" });
    expect(result).toContain("blocked");
  });

  it("should validate command input", async () => {
    const result = await bashTool.execute({ command: "" });
    expect(result).toContain("Error");
  });

  it("should validate input type", async () => {
    const result = await bashTool.execute({ command: null } as any);
    expect(result).toContain("Error");
  });

  it("should allow safe commands", async () => {
    const result = await bashTool.execute({ command: "pwd" });
    expect(result).toBeTruthy();
    expect(result).not.toContain("blocked");
  });
});

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { writeFile, unlink } from "fs/promises";
import { ReadTool } from "../../tools/read.js";

describe("ReadTool", () => {
  const testFile = "./test-file-read.txt";
  let readTool: ReadTool;

  beforeEach(async () => {
    readTool = new ReadTool();
    const content = "Line 1\nLine 2\nLine 3\nLine 4\nLine 5";
    await writeFile(testFile, content, "utf-8");
  });

  afterEach(async () => {
    try {
      await unlink(testFile);
    } catch {
      // File doesn't exist
    }
  });

  it("should read entire file content", async () => {
    const result = await readTool.execute({ path: testFile });
    expect(result).toContain("Line 1");
    expect(result).toContain("Line 5");
  });

  it("should read with offset and limit", async () => {
    const result = await readTool.execute({ path: testFile, offset: 2, limit: 2 });
    const lines = result.split("\n");
    expect(lines[0]).toBe("Line 2");
    expect(lines[1]).toBe("Line 3");
  });

  it("should handle offset only", async () => {
    const result = await readTool.execute({ path: testFile, offset: 3 });
    expect(result).toContain("Line 3");
    expect(result).toContain("Line 4");
    expect(result).toContain("Line 5");
  });

  it("should handle invalid path", async () => {
    const result = await readTool.execute({ path: "./non-existent-file.txt" });
    expect(result).toContain("Error");
  });

  it("should validate input type", async () => {
    const result = await readTool.execute({
      path: "",
    } as any);
    expect(result).toContain("Error");
  });
});

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { readFile, unlink, rm } from "fs/promises";
import { WriteTool } from "../../tools/write.js";

describe("WriteTool", () => {
  const testFile = "./test-file-write.txt";
  const testDir = "./test-dir-write";
  let writeTool: WriteTool;

  beforeEach(() => {
    writeTool = new WriteTool();
  });

  afterEach(async () => {
    try { await unlink(testFile); } catch { /* */ }
    try { await rm(testDir, { recursive: true, force: true }); } catch { /* */ }
  });

  it("should create a new file", async () => {
    const content = "Test content";
    const result = await writeTool.execute({ path: testFile, content });
    expect(result).toContain("correctamente");
    const fileContent = await readFile(testFile, "utf-8");
    expect(fileContent).toBe(content);
  });

  it("should overwrite existing file", async () => {
    await writeTool.execute({ path: testFile, content: "Original" });
    await writeTool.execute({ path: testFile, content: "Updated" });
    const content = await readFile(testFile, "utf-8");
    expect(content).toBe("Updated");
  });

  it("should create nested directories", async () => {
    const nestedPath = `${testDir}/nested/path/file.txt`;
    const result = await writeTool.execute({
      path: nestedPath,
      content: "Nested content",
    });
    expect(result).toContain("correctamente");
    const fileContent = await readFile(nestedPath, "utf-8");
    expect(fileContent).toBe("Nested content");
  });

  it("should validate path is not empty", async () => {
    const result = await writeTool.execute({ path: "", content: "Test" });
    expect(result).toContain("Error");
  });

  it("should validate input types", async () => {
    const result = await writeTool.execute({
      path: 123,
      content: "Test",
    } as any);
    expect(result).toContain("Error");
  });

  it("should handle large content", async () => {
    const largeContent = "x".repeat(10000);
    const result = await writeTool.execute({ path: testFile, content: largeContent });
    expect(result).toContain("correctamente");
    const fileContent = await readFile(testFile, "utf-8");
    expect(fileContent.length).toBe(10000);
  });
});

