import { logger } from "./logger.js";

interface Config {
  anthropicApiKey: string;
  openrouterApiKey: string;
  model: string;
  maxTokens: number;
  maxSteps: number;
  maxContextMessages: number;
  maxContextTokens: number;
  nodeEnv: string;
  screenPadding: number;
}

function validateEnv(): Config {
  logger.info("Validating environment variables...");

  // OpenRouter es el provider por defecto (ver #18 para selección dinámica).
  const openrouterApiKey = process.env.OPENROUTER_API_KEY;
  if (!openrouterApiKey) {
    logger.error("Missing required env var: OPENROUTER_API_KEY");
    throw new Error("OPENROUTER_API_KEY environment variable is required. Create a .env file or set it in ~/.omega/.env");
  }

  const apiKey = process.env.ANTHROPIC_API_KEY || "";

  const model = process.env.MODEL || "claude-haiku-4-5-20251001";
  const maxTokens = parseInt(process.env.MAX_TOKENS || "1024", 10);
  const maxSteps = parseInt(process.env.MAX_STEPS || "15", 10);
  const maxContextMessages = parseInt(process.env.MAX_CONTEXT_MESSAGES || "50", 10);
  const maxContextTokens = parseInt(process.env.MAX_CONTEXT_TOKENS || "100000", 10);
  const nodeEnv = process.env.NODE_ENV || "development";
  const screenPadding = parseInt(process.env.SCREEN_PADDING || "0", 10);

  const config: Config = {
    anthropicApiKey: apiKey,
    openrouterApiKey,
    model,
    maxTokens,
    maxSteps,
    maxContextMessages,
    maxContextTokens,
    nodeEnv,
    screenPadding,
  };

  logger.info("Config loaded successfully", {
    model,
    maxTokens,
    maxSteps,
    nodeEnv,
  });
  return config;
}

export { Config, validateEnv };

import { faker } from "@faker-js/faker";
import { Config } from "../../config.js";

export class ConfigFactory {
  static createConfig(overrides?: Partial<Config>): Config {
    return {
      anthropicApiKey: overrides?.anthropicApiKey || faker.string.alphanumeric(32),
      openrouterApiKey: overrides?.openrouterApiKey || faker.string.alphanumeric(32),
      model: overrides?.model || "claude-haiku-4-5-20251001",
      maxTokens: overrides?.maxTokens || faker.number.int({ min: 512, max: 4096 }),
      maxSteps: overrides?.maxSteps || faker.number.int({ min: 5, max: 20 }),
      maxContextMessages: overrides?.maxContextMessages ?? 50,
      maxContextTokens: overrides?.maxContextTokens ?? 100_000,
      nodeEnv: overrides?.nodeEnv || "test",
      screenPadding: overrides?.screenPadding ?? 0,
    };
  }

  static createProductionConfig(overrides?: Partial<Config>): Config {
    return this.createConfig({
      nodeEnv: "production",
      maxTokens: 1024,
      maxSteps: 15,
      ...overrides,
    });
  }

  static createDevelopmentConfig(overrides?: Partial<Config>): Config {
    return this.createConfig({
      nodeEnv: "development",
      maxTokens: 2048,
      maxSteps: 20,
      ...overrides,
    });
  }
}

import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { validateEnv } from "../config.js";

describe("Config", () => {
  const originalEnv = process.env;

  beforeEach(() => {
    vi.resetModules();
    process.env = { ...originalEnv };
  });

  afterEach(() => {
    process.env = originalEnv;
  });

  it("should throw error if OPENROUTER_API_KEY is missing", () => {
    delete process.env.OPENROUTER_API_KEY;
    expect(() => validateEnv()).toThrow(
      "OPENROUTER_API_KEY",
    );
  });

  it("should use default values for optional env vars", () => {
    process.env.OPENROUTER_API_KEY = "test-key";
    delete process.env.MODEL;
    delete process.env.MAX_TOKENS;
    delete process.env.MAX_STEPS;
    delete process.env.NODE_ENV;

    const config = validateEnv();

    expect(config.openrouterApiKey).toBe("test-key");
    expect(config.model).toBe("claude-haiku-4-5-20251001");
    expect(config.maxTokens).toBe(1024);
    expect(config.maxSteps).toBe(15);
    expect(config.nodeEnv).toBe("development");
  });

  it("should parse custom environment variables", () => {
    process.env.OPENROUTER_API_KEY = "custom-key";
    process.env.MODEL = "claude-3-opus";
    process.env.MAX_TOKENS = "2048";
    process.env.MAX_STEPS = "20";
    process.env.NODE_ENV = "production";

    const config = validateEnv();

    expect(config.openrouterApiKey).toBe("custom-key");
    expect(config.model).toBe("claude-3-opus");
    expect(config.maxTokens).toBe(2048);
    expect(config.maxSteps).toBe(20);
    expect(config.nodeEnv).toBe("production");
  });});

