import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { existsSync, unlinkSync } from "fs";
import { OverrideManager } from "../../classifier/overrides.js";

const TEST_STORE = ".omega/test-classifier-overrides.json";

describe("OverrideManager", () => {
  beforeEach(() => {
    try { unlinkSync(TEST_STORE); } catch { /* */ }
  });

  afterEach(() => {
    try { unlinkSync(TEST_STORE); } catch { /* */ }
  });

  describe("lookup", () => {
    it("should return null when no overrides exist", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      expect(mgr.lookup("ls -la")).toBeNull();
    });

    it("should match exact patterns (manual first)", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.add({ pattern: "ls -la", verdict: "safe", reason: "", source: "manual" });
      await mgr.add({ pattern: "ls *", verdict: "dangerous", reason: "", source: "learned" });

      // Exact match wins over wildcard
      const result = mgr.lookup("ls -la");
      expect(result).not.toBeNull();
      expect(result!.verdict).toBe("safe");
      expect(result!.source).toBe("manual");
    });

    it("should match wildcard patterns", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.add({ pattern: "git push*", verdict: "dangerous", reason: "", source: "manual" });

      expect(mgr.lookup("git push origin main")!.verdict).toBe("dangerous");
      expect(mgr.lookup("git push")!.verdict).toBe("dangerous");
      expect(mgr.lookup("git pull")).toBeNull();
    });

    it("should match regex patterns", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.add({ pattern: "/^npm (test|build)$/", verdict: "safe", reason: "", source: "manual" });

      expect(mgr.lookup("npm test")!.verdict).toBe("safe");
      expect(mgr.lookup("npm build")!.verdict).toBe("safe");
      expect(mgr.lookup("npm install")).toBeNull();
    });

    it("should prioritize manual over learned", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.add({ pattern: "npm test", verdict: "dangerous", reason: "", source: "learned" });
      await mgr.add({ pattern: "npm test", verdict: "safe", reason: "", source: "manual" });

      const result = mgr.lookup("npm test");
      expect(result!.verdict).toBe("safe");
      expect(result!.source).toBe("manual");
    });
  });

  describe("learn", () => {
    it("should create a new learned override", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.learn("some command", "safe");
      const override = mgr.lookup("some command");
      expect(override).not.toBeNull();
      expect(override!.source).toBe("learned");
      expect(override!.count).toBe(1);
    });

    it("should increment count on repeated learning", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.learn("some command", "safe");
      await mgr.learn("some command", "safe");
      await mgr.learn("some command", "dangerous");

      // Now let's check the list
      const list = mgr.list();
      const learned = list.find(o => o.pattern === "some command");
      expect(learned).not.toBeNull();
      expect(learned!.count).toBe(3);
      expect(learned!.verdict).toBe("dangerous"); // last learned wins
    });
  });

  describe("remove", () => {
    it("should remove manual overrides", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.add({ pattern: "rm -rf", verdict: "dangerous", reason: "", source: "manual" });
      const removed = await mgr.remove("rm -rf");
      expect(removed).toBe(true);
      expect(mgr.lookup("rm -rf")).toBeNull();
    });

    it("should not remove learned overrides via remove()", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.learn("some command", "safe");
      const removed = await mgr.remove("some command");
      expect(removed).toBe(false);
    });
  });

  describe("list", () => {
    it("should return overrides ordered: manual first, then learned", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.learn("cmd1", "safe");
      await mgr.add({ pattern: "cmd2", verdict: "dangerous", reason: "", source: "manual" });
      await mgr.learn("cmd3", "dangerous");

      const list = mgr.list();
      expect(list[0].source).toBe("manual");
      expect(list[1].source).toBe("learned");
      expect(list[2].source).toBe("learned");
    });
  });

  describe("getFewShotExamples", () => {
    it("should return relevant examples for a command prefix", async () => {
      const mgr = await OverrideManager.load(".omega/test-classifier-overrides.json");
      await mgr.learn("git status", "safe");
      await mgr.learn("git diff", "safe");
      await mgr.learn("npm test", "safe");
      await mgr.learn("npm install", "dangerous");

      const examples = mgr.getFewShotExamples("git push", 2);
      expect(examples.length).toBeLessThanOrEqual(2);
      // Should include git-related overrides
      const hasGit = examples.some(o => o.pattern.startsWith("git"));
      expect(hasGit).toBe(true);
    });
  });
});

import { describe, it, expect, beforeEach, vi } from "vitest";
import { BashTool, type BashConfirmCallback } from "../../tools/bash.js";
import { CommandClassifier } from "../../classifier/classifier.js";
import { OverrideManager } from "../../classifier/overrides.js";

describe("BashTool with classifier", () => {
  let overrides: OverrideManager;

  beforeEach(async () => {
    overrides = await OverrideManager.load(".omega/test-bash-classifier-overrides.json");
  });

  it("should execute command directly when classifier returns safe", async () => {
    const mockClassify = vi.fn().mockResolvedValue({
      verdict: "safe" as const,
      reason: "Comando inofensivo",
      source: "classifier" as const,
    });

    const classifier = new CommandClassifier(overrides, "test-key");
    // Mockear classify
    vi.spyOn(classifier, "classify").mockImplementation(mockClassify);

    const onConfirm = vi.fn();
    const tool = new BashTool({ classifier, onConfirm });

    const result = await tool.execute({ command: "echo hello" });

    expect(result).toContain("hello");
    expect(mockClassify).toHaveBeenCalledWith("echo hello");
    expect(onConfirm).not.toHaveBeenCalled();
  });

  it("should ask confirmation when classifier returns dangerous and user confirms", async () => {
    const mockClassify = vi.fn().mockResolvedValue({
      verdict: "dangerous" as const,
      reason: "Modifica el filesystem",
      source: "classifier" as const,
    });

    const classifier = new CommandClassifier(overrides, "test-key");
    vi.spyOn(classifier, "classify").mockImplementation(mockClassify);
    vi.spyOn(classifier, "learnOverride").mockResolvedValue(undefined);

    const onConfirm: BashConfirmCallback = vi.fn().mockResolvedValue(true);
    const tool = new BashTool({ classifier, onConfirm });

    const result = await tool.execute({ command: "rm file.txt" });

    expect(result).toContain("rm");
    expect(mockClassify).toHaveBeenCalledWith("rm file.txt");
    expect(onConfirm).toHaveBeenCalled();
    expect(classifier.learnOverride).toHaveBeenCalledWith("rm file.txt", "safe");
  });

  it("should reject when classifier returns dangerous and user declines", async () => {
    const mockClassify = vi.fn().mockResolvedValue({
      verdict: "dangerous" as const,
      reason: "Modifica archivos del proyecto",
      source: "classifier" as const,
    });

    const classifier = new CommandClassifier(overrides, "test-key");
    vi.spyOn(classifier, "classify").mockImplementation(mockClassify);
    vi.spyOn(classifier, "learnOverride").mockResolvedValue(undefined);

    const onConfirm: BashConfirmCallback = vi.fn().mockResolvedValue(false);
    const tool = new BashTool({ classifier, onConfirm });

    const result = await tool.execute({ command: "rm important.txt" });

    expect(result).toContain("Error");
    expect(result).toContain("rechazó");
    expect(mockClassify).toHaveBeenCalledWith("rm important.txt");
    expect(onConfirm).toHaveBeenCalled();
    expect(classifier.learnOverride).toHaveBeenCalledWith("rm important.txt", "dangerous");
  });

  it("should use override instead of classifying when pattern matches", async () => {
    // Agregamos un override manual
    await overrides.add({ pattern: "npm test", verdict: "safe", reason: "Confío", source: "manual" });

    const classifier = new CommandClassifier(overrides, "test-key");
    // El classify real debería devolver el override sin llamar al LLM
    const result_classify = await classifier.classify("npm test");
    expect(result_classify.verdict).toBe("safe");
    expect(result_classify.source).toBe("override");

    const onConfirm = vi.fn();
    const tool = new BashTool({ classifier, onConfirm });

    const result = await tool.execute({ command: "npm test" });
    // npm test probablemente falle porque no hay package.json en test scope,
    // pero debería intentar ejecutarse (no ser bloqueado)
    expect(onConfirm).not.toHaveBeenCalled();
  });

  it("should work without classifier (backward compatible)", async () => {
    const tool = new BashTool(); // sin opciones
    const result = await tool.execute({ command: "echo hello" });
    expect(result).toContain("hello");
  });
});

