import { exec } from "child_process";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";

type BashInput = { command: string };

const TIMEOUT_MS = 30_000; // matar comandos colgados a los 30s
const MAX_BUFFER = 10 * 1024 * 1024; // 10MB de stdout/stderr

// Esto NO es un sandbox: es un guardarraíl best-effort contra los
// errores más groseros. Un comando malicioso decidido lo puede saltar.
// Para aislamiento real haría falta correr en un contenedor/VM.
const BLOCKED_PATTERNS = [
  /\brm\s+-[a-z]*[rf]/i, // rm con -r o -f en cualquier orden/combinación
  /:\s*\(\s*\)\s*\{.*:.*\|.*:.*\}/, // fork bomb
  />\s*\/dev\/(sd|nvme|disk|hd)/i, // escritura directa a un disco
  /\bmkfs\b/i, // formatear un filesystem
  /\bdd\b.*\bof=\/dev\//i, // dd hacia un device
  /\b(shutdown|reboot|halt|poweroff)\b/i, // apagar/reiniciar la máquina
];

// Patrones que involucran archivos .env (lectura o escritura)
const ENV_ACCESS_PATTERNS = [
  /(^|[|&;`\s])(cat|head|tail|less|more|bat|nl|od|strings)\s+.*\.env\b/i,
  /(^|[|&;`\s])(cp|mv)\s+.*\.env\b/i,
  /(^|[|&;`\s])(cp|mv)\s+\S+\s+.*\.env\b/i,
  />>>?\s*.*\.env\b/i,        // > .env, >> .env
  /(^|[|&;`\s])echo\s+.*>>>?\s*.*\.env\b/i,
  /(^|[|&;`\s])tee\s+.*\.env\b/i,
  /(^|[|&;`\s])(grep|rg|awk|sed|cut|sort|uniq|diff|comm|join|paste)\s+.*\.env\b/i,
  /\.env[\s'"]*$/i,            // cualquier comando cuyo último arg sea .env
];

export class BashTool extends Tool<BashInput, string> {
  constructor() {
    super({
      name: "bash",
      description: "Ejecuta un comando bash y devuelve stdout y stderr",
      schema: {
        type: "object",
        properties: {
          command: {
            type: "string",
            description: "El comando bash a ejecutar",
          },
        },
        required: ["command"],
      },
    });
  }

  private isCommandBlocked(command: string): boolean {
    return BLOCKED_PATTERNS.some((pattern) => pattern.test(command))
      || ENV_ACCESS_PATTERNS.some((pattern) => pattern.test(command));
  }

  async execute({ command }: BashInput): Promise<string> {
    try {
      if (!command || typeof command !== "string") {
        logger.error("Invalid bash command input", { command });
        return "Error: command must be a non-empty string";
      }

      if (this.isCommandBlocked(command)) {
        logger.warn("Blocked dangerous command", { command });
        return "Error: This command is blocked for security reasons";
      }

      logger.info("Executing bash command", { command });
      const result = await new Promise<string>((resolve, reject) => {
        exec(command, {
          encoding: "buffer" as BufferEncoding,
          timeout: TIMEOUT_MS,
          maxBuffer: MAX_BUFFER,
        }, (error, stdout, stderr) => {
          // juntar stdout y stderr
          const out = Buffer.isBuffer(stdout) ? stdout.toString("utf-8") : String(stdout);
          const err = Buffer.isBuffer(stderr) ? stderr.toString("utf-8") : String(stderr);
          const combined = (out + (err ? err : "")).trim();
          if (error && !combined) {
            reject(error);
          } else {
            resolve(combined || (error?.message ?? ""));
          }
        });
      });
      logger.info("Command executed successfully");
      return result;
    } catch (err: unknown) {
      const error = err as { code?: string; signal?: string; stderr?: string; stdout?: string; message?: string };
      if (error.code === "ETIMEDOUT" || error.signal === "SIGTERM") {
        const msg = `Error: command timed out after ${TIMEOUT_MS}ms`;
        logger.warn("Bash command timed out", { command });
        return msg;
      }
      const errorMsg = error.stderr || error.stdout || error.message || String(err);
      logger.error("Bash command failed", { command, error: errorMsg });
      return errorMsg;
    }
  }
}

import { readFile } from "fs/promises";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";
import { isEnvFile, ENV_BLOCK_MESSAGE } from "./env-guard.js";

type ReadInput = { path: string; offset?: number; limit?: number };

export class ReadTool extends Tool<ReadInput, string> {
  constructor() {
    super({
      name: "read",
      description: "Devuelve el contenido de un archivo",
      schema: {
        type: "object",
        properties: {
          path: { type: "string", description: "Ruta del archivo a leer" },
          offset: {
            type: "number",
            description: "Línea desde la que empezar (1-indexed, opcional)",
          },
          limit: {
            type: "number",
            description: "Máximo de líneas a leer (opcional)",
          },
        },
        required: ["path"],
      },
    });
  }

  async execute(input: unknown): Promise<string> {
    try {
      if (typeof input !== "object" || input === null) {
        throw new Error("Input must be an object with path");
      }

      const { path, offset, limit } = input as ReadInput;

      if (typeof path !== "string" || !path.trim()) {
        throw new Error("path must be a non-empty string");
      }

      if (isEnvFile(path)) {
        logger.warn("Blocked read of env file", { path });
        return ENV_BLOCK_MESSAGE;
      }

      logger.info("Reading file", { path, offset, limit });
      const content = await readFile(path, "utf-8");

      // sin offset/limit: devolvemos el archivo entero
      if (offset === undefined && limit === undefined) {
        logger.info("File read successfully", { path, lines: content.split("\n").length });
        return content;
      }

      const lines = content.split("\n");
      const start = offset ? offset - 1 : 0; // offset es 1-indexed
      const end = limit ? start + limit : lines.length;
      const result = lines.slice(start, end).join("\n");
      logger.info("File slice read successfully", { path, start, end });
      return result;
    } catch (err: unknown) {
      const pathName = input !== null && typeof input === "object" && "path" in (input as object)
        ? String((input as ReadInput).path)
        : String(input);
      const errorMsg = `Error reading ${pathName}: ${err instanceof Error ? err.message : String(err)}`;
      logger.error(errorMsg);
      return errorMsg;
    }
  }
}

import { writeFile, mkdir } from "fs/promises";
import { dirname } from "path";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";
import { isEnvFile, ENV_BLOCK_MESSAGE } from "./env-guard.js";

type WriteInput = { path: string; content: string };

export class WriteTool extends Tool<WriteInput, string> {
  constructor() {
    super({
      name: "write",
      description:
        "Crea un archivo nuevo o sobrescribe uno existente con el contenido dado",
      schema: {
        type: "object",
        properties: {
          path: { type: "string", description: "Ruta del archivo a escribir" },
          content: {
            type: "string",
            description: "Contenido completo a escribir en el archivo",
          },
        },
        required: ["path", "content"],
      },
    });
  }

  async execute(input: unknown): Promise<string> {
    try {
      // Validar que input es un objeto
      if (typeof input !== "object" || input === null) {
        throw new Error("Input must be an object with path and content");
      }

      const { path, content } = input as Record<string, unknown>;

      // Validar tipos
      if (typeof path !== "string" || typeof content !== "string") {
        throw new Error("path and content must be strings");
      }

      if (!path.trim()) {
        throw new Error("path cannot be empty");
      }

      if (isEnvFile(path)) {
        logger.warn("Blocked write to env file", { path });
        return ENV_BLOCK_MESSAGE;
      }

      logger.info("Writing file", { path, size: content.length });
      await mkdir(dirname(path), { recursive: true });
      await writeFile(path, content, "utf-8");
      logger.info("File written successfully", { path });
      return `Escrito ${path} correctamente.`;
    } catch (err: unknown) {
      const errorMsg = `Error writing file: ${err instanceof Error ? err.message : String(err)}`;
      logger.error(errorMsg, { error: err });
      return errorMsg;
    }
  }
}

import { readFile, writeFile } from "fs/promises";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";
import { isEnvFile, ENV_BLOCK_MESSAGE } from "./env-guard.js";

export type EditInput = { path: string; oldText: string; newText: string };

export class EditTool extends Tool<EditInput, string> {
  constructor() {
    super({
      name: "edit",
      description: "Reemplaza quirúrgicamente texto exacto dentro de un archivo",
      schema: {
        type: "object",
        properties: {
          path: { type: "string", description: "Ruta del archivo a editar" },
          oldText: {
            type: "string",
            description:
              "Texto exacto a reemplazar (debe matchear carácter por carácter, incluido el whitespace)",
          },
          newText: {
            type: "string",
            description: "Texto nuevo que reemplaza al viejo",
          },
        },
        required: ["path", "oldText", "newText"],
      },
    });
  }

  async execute(input: unknown): Promise<string> {
    try {
      if (typeof input !== "object" || input === null) {
        throw new Error("Input must be an object with path, oldText, and newText");
      }

      const { path, oldText, newText } = input as EditInput;

      if (typeof path !== "string" || typeof oldText !== "string" || typeof newText !== "string") {
        throw new Error("path, oldText, and newText must be strings");
      }

      if (isEnvFile(path)) {
        logger.warn("Blocked edit of env file", { path });
        return ENV_BLOCK_MESSAGE;
      }

      logger.info("Editing file", { path, oldTextLength: oldText.length, newTextLength: newText.length });

      let content: string;
      try {
        content = await readFile(path, "utf-8");
      } catch (err: unknown) {
        throw new Error(`Could not read ${path}: ${err instanceof Error ? err.message : String(err)}`);
      }

      const occurrences = content.split(oldText).length - 1;

      if (occurrences === 0) {
        logger.warn("Text not found in file", { path });
        throw new Error(`Text to replace not found in ${path}. Ensure it matches exactly.`);
      }

      if (occurrences > 1) {
        logger.warn("Multiple occurrences found", { path, occurrences });
        throw new Error(`Text appears ${occurrences} times in ${path}, ambiguous. Include more context.`);
      }

      const updated = content.replace(oldText, newText);
      try {
        await writeFile(path, updated, "utf-8");
      } catch (err: unknown) {
        throw new Error(`Could not write ${path}: ${err instanceof Error ? err.message : String(err)}`);
      }

      logger.info("File edited successfully", { path });
      return `Editado ${path} correctamente.`;
    } catch (err: unknown) {
      const errorMsg = err instanceof Error ? err.message : `Unknown error editing file`;
      logger.error(errorMsg, { error: err });
      return `Error: ${errorMsg}`;
    }
  }
}

import { exec } from "child_process";
import { stat } from "fs/promises";
import { resolve, relative } from "path";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";
import { isEnvFile } from "./env-guard.js";

type GrepInput = {
  pattern: string;
  path?: string;
  include?: string;
  contextLines?: number;
  maxResults?: number;
};

const TIMEOUT_MS = 10_000;
const MAX_BUFFER = 5 * 1024 * 1024;
const DEFAULT_MAX_RESULTS = 50;

export class GrepTool extends Tool<GrepInput, string> {
  constructor() {
    super({
      name: "grep",
      description:
        "Busca un patrón regex en archivos del proyecto, devolviendo número de línea, columna y contexto alrededor de cada match.",
      schema: {
        type: "object",
        properties: {
          pattern: {
            type: "string",
            description: "Patrón regex (grep -E) a buscar. Ej: 'export.*class', 'TODO'",
          },
          path: {
            type: "string",
            description:
              "Directorio o archivo donde buscar. Por defecto: el directorio actual (cwd).",
          },
          include: {
            type: "string",
            description:
              "Glob para filtrar archivos (ej: '*.ts', 'src/**/*.js'). Se pasa a grep con --include.",
          },
          contextLines: {
            type: "number",
            description:
              "Líneas de contexto antes y después de cada match (default: 2).",
          },
          maxResults: {
            type: "number",
            description:
              `Máximo de resultados a devolver (default: ${DEFAULT_MAX_RESULTS}).`,
          },
        },
        required: ["pattern"],
      },
    });
  }

  async execute(input: GrepInput): Promise<string> {
    const {
      pattern,
      path: searchPath = ".",
      include,
      contextLines = 2,
      maxResults = DEFAULT_MAX_RESULTS,
    } = input;

    if (!pattern || typeof pattern !== "string") {
      return "Error: pattern es requerido y debe ser un string";
    }

    const absPath = resolve(searchPath);
    if (isEnvFile(absPath)) {
      return "Error: no se puede buscar en archivos .env por seguridad";
    }

    let isFile = false;
    try {
      const s = await stat(absPath);
      isFile = s.isFile();
    } catch {
      // path doesn't exist, grep will fail gracefully
    }

    try {
      const args: string[] = [
        "-rnE",          // recursivo, números de línea, regex extendido
        "--color=never", // sin códigos ANSI
        "-C", String(contextLines),
      ];

      if (include) {
        args.push("--include", include);
      }

      // Escapar el patrón para shell
      args.push("-e", pattern);
      args.push(absPath);

      const result = await new Promise<string>((resolve, reject) => {
        exec(`grep ${args.map(a => `'${a.replace(/'/g, "'\\''")}'`).join(" ")}`, {
          encoding: "buffer" as BufferEncoding,
          timeout: TIMEOUT_MS,
          maxBuffer: MAX_BUFFER,
          cwd: process.cwd(),
        }, (error, stdout, stderr) => {
          const out = Buffer.isBuffer(stdout) ? stdout.toString("utf-8") : String(stdout);
          const err = Buffer.isBuffer(stderr) ? stderr.toString("utf-8") : String(stderr);
          // grep devuelve exit code 1 cuando no hay matches (no es error)
          if (error && error.code !== 1 && !out) {
            reject(err || error);
          } else {
            resolve(out);
          }
        });
      });

      if (!result.trim()) {
        return "Sin resultados.";
      }

      const lines = result.trim().split("\n");
      const limited = lines.slice(0, maxResults * ((contextLines * 2) + 1 + 1)); // matches + context + separators
      const truncated = lines.length > limited.length
        ? limited.join("\n") + `\n... (${lines.length - limited.length} líneas omitidas, ${Math.round(lines.length / (contextLines * 2 + 1))} resultados aprox.)`
        : limited.join("\n");

      // Formatear: agregar filepath relativo y cabecera
      const header = `${limited.length} líneas de resultados`;
      const summary = `\n-- grep "${pattern}" en ${relative(process.cwd(), absPath) || "."} --`;

      return `${summary}\n${truncated}`;
    } catch (err: unknown) {
      const error = err as { code?: string; signal?: string; stderr?: string; stdout?: string; message?: string };
      // grep devuelve exit code 1 cuando no hay matches (no es error)
      if (error.code === "ETIMEDOUT" || error.signal === "SIGTERM") {
        return `Error: búsqueda cancelada por timeout (${TIMEOUT_MS}ms)`;
      }
      if (error.stderr && !error.stderr.includes("No such file")) {
        logger.error("Grep command failed", { pattern, error: error.stderr || error.message });
        return `Error: ${error.stderr || error.message}`;
      }
      return "Sin resultados.";
    }
  }
}

