import type { Command } from "./command.js";
import type { AppContext } from "../app-context.js";
import { dim, bold } from "../tui/theme.js";

/**
 * /overrides - gestiona los overrides del clasificador de comandos.
 *
 * /overrides                              -> lista todos
 * /overrides add safe "npm run *" "razón" -> agrega override manual SAFE
 * /overrides add dangerous "git push*" "razón" -> agrega override manual DANGEROUS
 * /overrides remove "npm run *"           -> elimina override manual
 */
export const overridesCommand: Command<string[]> = {
  name: "overrides",
  description:
    "Gestiona overrides del clasificador de comandos. Sin argumentos: lista todos.",
  async execute(args, ctx) {
    const classifier = ctx.classifier;
    if (!classifier) {
      ctx.screen.printAbove(
        dim("El clasificador de comandos no está activo en esta sesión."),
      );
      return;
    }

    const overrides = classifier.overrides;

